namespace optiling {

static constexpr uint32_t UB_BUDGET_BYTES = 192 * 1024;
static constexpr uint32_t ALIGN_ELEMS = 256;
static constexpr uint32_t MAX_BLOCKS = 24;

static inline uint32_t AlignDown(uint32_t x, uint32_t a)
{
    return (x / a) * a;
}

static inline uint32_t CeilDiv(uint32_t a, uint32_t b)
{
    return (a + b - 1u) / b;
}

static ge::graphStatus TilingFunc(gert::TilingContext *context)
{
    GemmBiasAddHardtanhMishGroupNormCustomTilingData tiling;

    const gert::Shape *x_shape = context->GetInputShape(0);
    const gert::Shape *w_shape = context->GetInputShape(1);

    const uint32_t rows = static_cast<uint32_t>(x_shape->GetOriginShape().GetDim(0));
    const uint32_t inFeat = static_cast<uint32_t>(x_shape->GetOriginShape().GetDim(x_shape->GetOriginShape().GetDimNum()-1));
    const uint32_t outFeat = static_cast<uint32_t>(w_shape->GetOriginShape().GetDim(0));

    const gert::RuntimeAttrs *attrs = context->GetAttrs();
    const int32_t *numGroupsPtr = attrs->GetAttrPointer<int32_t>(0);
    const float *epsilonPtr = attrs->GetAttrPointer<float>(1);
    const uint32_t numGroups = static_cast<uint32_t>(*numGroupsPtr);
    const float epsilon = *epsilonPtr;

    // group size
    uint32_t groupSize = (numGroups == 0) ? outFeat : (outFeat / numGroups);
    if (groupSize == 0) groupSize = 1;

    // UB usage estimate:
    //   xTile: tileK
    //   wTile: tileK
    //   tmpDot: tileK
    //   acc: groupSize
    //   v: groupSize
    //   gamma: groupSize
    //   beta: groupSize
    //   scalars: small
    // Total floats ≈ 3*tileK + 4*groupSize + 8
    // Convert to bytes with 4 per float
    uint32_t maxTileK = 0;
    if (UB_BUDGET_BYTES > (4u * (4u * groupSize + 8u))) {
        maxTileK = (UB_BUDGET_BYTES - 4u * (4u * groupSize + 8u)) / 12u; // bytes per float group, 3*tileK*4 bytes -> 12
    } else {
        maxTileK = ALIGN_ELEMS;
    }
    maxTileK = AlignDown(maxTileK, ALIGN_ELEMS);
    if (maxTileK < ALIGN_ELEMS) maxTileK = ALIGN_ELEMS;
    if (maxTileK > inFeat) {
        uint32_t aligned = AlignDown(inFeat, ALIGN_ELEMS);
        maxTileK = (aligned > 0) ? aligned : inFeat;
    }

    uint32_t tileK = maxTileK;
    if (tileK == 0) tileK = inFeat;

    // blockDim based on rows
    uint32_t blockDim = rows;
    if (blockDim == 0) blockDim = 1;
    if (blockDim > MAX_BLOCKS) blockDim = MAX_BLOCKS;
    if (blockDim < 1) blockDim = 1;

    context->SetBlockDim(blockDim);

    tiling.set_rows(rows);
    tiling.set_inFeat(inFeat);
    tiling.set_outFeat(outFeat);
    tiling.set_tileK(tileK);
    tiling.set_groupSize(groupSize);
    tiling.set_numGroups(numGroups == 0 ? 1u : numGroups);
    tiling.set_blockDim(blockDim);
    tiling.set_epsilon(epsilon);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *currentWorkspace = context->GetWorkspaceSizes(1);
    currentWorkspace[0] = 0;
    return ge::GRAPH_SUCCESS;
}

